window.handleBarcode = function (e) {
  if (e.key !== 'Enter') return;
  var val = document.getElementById('inp_barcode').value.trim();
  if (!val) return;
  appsmith.updateModel({
    searchBarcode: val
  });
  appsmith.triggerEvent('onBarcodeSearch');
};
window.handleSerial = function (e) {
  if (e.key !== 'Enter') return;
  var val = document.getElementById('inp_serial').value.trim();
  if (!val) return;
  appsmith.updateModel({
    searchSerial: val
  });
  appsmith.triggerEvent('onSerialSearch');
};
window.handleCollection = function (e) {
  if (e.key !== 'Enter') return;
  var val = document.getElementById('inp_collection').value.trim();
  if (!val) return;
  appsmith.updateModel({
    searchCollection: val
  });
  appsmith.triggerEvent('onCollectionSearch');
};
appsmith.onReady(function () {
  // Widget ready
});

